for (const [pageNum, qList] of sortedPages) {
  console.log(`[SURGERY] Targeting Page ${pageNum}...`);

  const pageMarker = `aria-label="Page ${pageNum}"`;
  const markerIdx = html.indexOf(pageMarker);

  if (markerIdx !== -1) {
    // STRATEGY 5: Look for the specific boundary where the page wrapper ends.
    // This looks for the double-div closing pattern found in the sample HTML.
    const boundaryPattern = '</div>\n\n</div>';
    let insertIdx = html.indexOf(boundaryPattern, markerIdx);

    if (insertIdx !== -1) {
      // Offset by the length of the pattern to get outside the containers
      insertIdx += boundaryPattern.length;
      const dataPayload = JSON.stringify(qList);

      const injection = `\n\n<!-- MIRON_TEAR_START -->\n<div class="miron-portal-container">\n  <div class="miron-challenge-anchor" data-questions='${dataPayload.replace(/'/g, "&apos;")}'></div>\n</div>\n<!-- MIRON_TEAR_END -->\n\n`;

      html = html.slice(0, insertIdx) + injection + html.slice(insertIdx);
      console.log(`[SURGERY] SUCCESS: Page ${pageNum} boundary tear applied.`);
    } else {
       // Fallback to single div if double isn't found
       const singleDivIdx = html.indexOf('</div>', html.indexOf('</section>', markerIdx));
       if (singleDivIdx !== -1) {
          const pos = singleDivIdx + 6;
          html = html.slice(0, pos) + `<div class="miron-portal-container"><div class="miron-challenge-anchor" data-questions='${JSON.stringify(qList).replace(/'/g, "&apos;")}'></div></div>` + html.slice(pos);
          console.log(`[SURGERY] SEMI-SUCCESS: Page ${pageNum} used single-div fallback.`);
       } else {
          console.warn(`[SURGERY] FAILED: No boundary found for Page ${pageNum}`);
       }
    }
  } else {
    console.warn(`[SURGERY] FAILED: Page marker ${pageNum} not found.`);
  }
}

